// Define a function to correct port mappings
function correctPortMappings(containerConfig) {
  var correctedConfig = {
    container: containerConfig.container,
    port_mappings: []
  };

  containerConfig.port_mappings.forEach(function(portMapping) {
    if (portMapping.exposed_port === portMapping.host_port) {
      correctedConfig.port_mappings.push(portMapping);
    } else {
      correctedConfig.port_mappings.push({
        exposed_port: portMapping.exposed_port,
        host_port: portMapping.exposed_port
      });
    }
  });

  return correctedConfig;
}

