class Solution:
    def correctPortMappings(self, containerConfig):
        correctedConfig = {
            'container': containerConfig['container'],
            'port_mappings': []
        }

        for portMapping in containerConfig['port_mappings']:
            if portMapping['exposed_port'] == portMapping['host_port']:
                correctedConfig['port_mappings'].append(portMapping)
            else:
                correctedConfig['port_mappings'].append({
                    'exposed_port': portMapping['exposed_port'],
                    'host_port': portMapping['exposed_port']
                })

        return correctedConfig

